-- Sync page sections from code defaults (includes image_urls for animated gallery cards)
on conflict (page_key, section_key) do update set
  label = excluded.label,
  heading = excluded.heading,
  subheading = excluded.subheading,
  body_text = excluded.body_text,
  badge_text = excluded.badge_text,
  primary_btn_text = excluded.primary_btn_text,
  primary_btn_url = excluded.primary_btn_url,
  secondary_btn_text = excluded.secondary_btn_text,
  secondary_btn_url = excluded.secondary_btn_url,
  media_url = excluded.media_url,
  media_secondary_url = excluded.media_secondary_url,
  enabled = excluded.enabled,
  order_index = excluded.order_index,
  items_json = excluded.items_json,
  settings_json = excluded.settings_json,
  updated_at = now();
