  ('home', 'hero', 'Hero', 'Your Gateway to the World''s Best Universities', 'Trusted by 10,000+ students. Free consultation. Expert counsellors. 400+ university partners.', '', 'USA-Based Study Abroad Consultancy', 'Start Your Journey', '/apply', 'Book Free Consultation', '/contact', '', '', true, 1, '[]'::jsonb, '{"overlay_opacity":0.56,"background_images":[{"image_url":"","title":"Slide 1"}],"stats":[{"value":400,"suffix":"+","label":"University Partners"},{"value":15,"suffix":"+","label":"Years Experience"},{"value":10000,"suffix":"+","label":"Students Placed"},{"value":98,"suffix":"%","label":"Visa Success Rate"}],"feature_card":{"kicker":"Admission Roadmap","heading":"From shortlist to offer letter","body":"Clear counselling, faster applications, stronger visa preparation.","pills":["400+ Partners","Visa Experts","Pre-Departure Support"]},"compact_card":{"title":"Trusted by families","body":"Personal support for every milestone."}}'::jsonb),
