  ('home', 'why_nexora', 'Why Nexora', 'Why 10,000+ Students Choose Nexora', 'We guide students from their first counselling call to visa approval, pre-departure planning, and arrival.', '', 'Why Nexora', '', '', '', '', '', '', true, 3, '[{"text":"Priority agent with 400+ institutions"},{"text":"Dedicated specialist counsellors"},{"text":"Free consultation and application support"},{"text":"Pre-departure briefings included"},{"text":"Expert visa team with 98% success rate"},{"text":"SIM card provided before travel"}]'::jsonb, '{"visual_badge_value":98,"visual_badge_suffix":"%","visual_badge_label":"Visa success rate","visual_heading":"Applications prepared with precision","visual_body":"We keep every document, deadline, and university response moving in the right order.","link_text":"Learn More","link_url":"/about"}'::jsonb),
  ('home', 'how_it_works', 'How It Works', 'Your Journey in 5 Simple Steps', 'A structured process that keeps your application moving with clarity and confidence.', '', 'Simple Process', '', '', '', '', '', '', true, 4, '[{"title":"Book Free Consultation","description":"Speak with a counsellor about your goals, budget, and best-fit destinations."},{"title":"Prepare Your Documents","description":"We help you gather transcripts, passports, statements, and supporting materials."},{"title":"Meet Offer Conditions","description":"We track university feedback and guide you through any pending requirements."},{"title":"Visa Application","description":"Our team prepares your visa file carefully and keeps timelines on track."},{"title":"Fly & Arrive","description":"You leave with briefings, travel guidance, and arrival support already sorted."}]'::jsonb, '{}'::jsonb),
