  ('about', 'hero', 'Hero', 'We help students step confidently into global education.', 'For more than 15 years, Nexora Education has supported students with university applications, visa strategy, and practical preparation for life abroad.', '', 'About Nexora', '', '', '', '', '', '', true, 1, '[]'::jsonb, '{}'::jsonb),
  ('about', 'story', 'Story', 'From first consultation to arrival abroad, we stay close to the journey.', 'Nexora Education was built to make world-class education feel reachable for students and families worldwide. We combine destination expertise with a hands-on support model that keeps applications clear, timely, and realistic.', 'With 400+ institution partnerships and a strong network of student destinations, we continue to shape a study abroad experience that is ambitious, ethical, and deeply practical.', 'Our Story', '', '', '', '', '', '', true, 2, '[{"title":"400+ university partners","description":"Wide destination choice and direct application support."},{"title":"U.S.-based support","description":"Local guidance with a global admissions perspective."},{"title":"Student-first standards","description":"Student outcomes, trust, and consistency remain our benchmark."}]'::jsonb, '{"visual_tag":"15+ years of guidance","visual_heading":"Built on trust, outcomes, and informed advice","visual_body":"Our U.S.-based team has helped students access universities across the UK, Canada, Australia, the USA, Europe, Dubai, and beyond."}'::jsonb),
  ('about', 'mission_vision', 'Mission & Vision', '', '', '', '', '', '', '', '', '', '', true, 3, '[]'::jsonb, '{"mission":{"badge":"Mission","heading":"To help students access life-changing global education with clarity and confidence.","body":"We simplify study abroad by combining expert counselling, careful admissions preparation, and dependable visa guidance for students worldwide."},"vision":{"badge":"Vision","heading":"To become one of the most trusted bridges between global talent and the world''s best universities.","body":"We want every qualified student to feel seen, prepared, and connected to international opportunities that match their goals and potential."}}'::jsonb),
  ('about', 'values', 'Values', 'The principles that shape every student interaction.', 'We care deeply about trust, usefulness, and creating a process students can actually move through with confidence.', '', 'Our Values', '', '', '', '', '', '', true, 4, '[{"title":"Integrity","description":"We advise students honestly and build every recommendation around real fit, not pressure."},{"title":"Excellence","description":"Every application, statement, and visa file is handled with detail and professional care."},{"title":"Student-First","description":"Our process is designed around student goals, confidence, and long-term success."},{"title":"Innovation","description":"We keep improving how students research, apply, and prepare for their next chapter."},{"title":"Accessibility","description":"Expert study abroad guidance should feel approachable, responsive, and easy to understand."},{"title":"Global Mindset","description":"We connect local ambition to global opportunity with practical, future-focused guidance."}]'::jsonb, '{}'::jsonb),
  ('about', 'team', 'Team', 'The counsellors and advisors behind the student journey.', 'From admissions strategy to visa support, our team works across the full pathway and keeps every next step understandable.', '', 'Meet The Team', '', '', '', '', '', '', true, 5, '[]'::jsonb, '{}'::jsonb),
