  ('study_abroad', 'hero', 'Hero', 'Discover destinations that fit your ambitions, budget, and long-term goals.', 'Nexora helps students compare countries, prepare strong applications, access scholarships, and move confidently through the visa process.', '', 'Study Abroad', 'Start Application', '/apply', 'Book Consultation', '/contact', '', '', true, 1, '[]'::jsonb, '{"map_card_title":"Choose from 10+ destinations","map_card_body":"From the UK and Canada to Dubai, Europe, and Malaysia.","map_card_badge":"Global pathways"}'::jsonb),
  ('study_abroad', 'destinations', 'Destinations', 'Find the right country for your course and future plans.', 'Every destination has a different mix of tuition levels, work options, scholarship access, and post-study opportunities.', '', 'Destinations', '', '', '', '', '', '', true, 2, '[{"slug":"uk","code":"GB","name":"United Kingdom","summary":"High-ranking universities, broad scholarship options, and strong post-study pathways.","universities":["University of Manchester","University of Leeds","Coventry University"],"image_url":""},{"slug":"australia","code":"AU","name":"Australia","summary":"Global-quality teaching, student support, and vibrant multicultural campuses.","universities":["Deakin University","Griffith University","University of Adelaide"],"image_url":""},{"slug":"canada","code":"CA","name":"Canada","summary":"Welcoming student destinations with strong employability and migration interest.","universities":["University of Windsor","York University","University of Manitoba"],"image_url":""},{"slug":"usa","code":"US","name":"United States","summary":"Wide course choice, high research output, and dynamic campus communities.","universities":["Arizona State University","Pace University","University of South Florida"],"image_url":""},{"slug":"new-zealand","code":"NZ","name":"New Zealand","summary":"Supportive study environment with strong quality assurance and student wellbeing.","universities":["University of Auckland","Massey University","AUT"],"image_url":""},{"slug":"dubai","code":"AE","name":"Dubai","summary":"Modern city campuses, international branch institutions, and regional accessibility.","universities":["University of Birmingham Dubai","Middlesex Dubai","Heriot-Watt Dubai"],"image_url":""},{"slug":"europe","code":"EU","name":"Europe","summary":"Affordable options, diverse cultures, and expanding English-taught programmes.","universities":["EU Business School","University of Europe","Budapest Metropolitan University"],"image_url":""},{"slug":"malaysia","code":"MY","name":"Malaysia","summary":"Cost-effective programmes, branch campuses, and diverse student life.","universities":["Taylor''s University","Sunway University","UCSI University"],"image_url":""},{"slug":"turkey","code":"TR","name":"Turkey","summary":"Competitive tuition, cultural richness, and increasing scholarship availability.","universities":["Bahcesehir University","Istanbul Aydin University","Ozyegin University"],"image_url":""},{"slug":"china","code":"CN","name":"China","summary":"Technology-driven universities, strong research ecosystems, and expanding scholarship access.","universities":["Tsinghua University","Peking University","Fudan University"],"image_url":""}]'::jsonb, '{}'::jsonb),
  ('study_abroad', 'steps', 'How To Apply', 'Your journey in 5 guided steps.', 'We help you move from the first conversation to travel readiness with a structured, student-friendly process.', '', 'How To Apply', '', '', '', '', '', '', true, 3, '[{"title":"Book Free Consultation","description":"We assess your academic background, budget, goals, and the countries that match your priorities."},{"title":"Prepare Your Documents","description":"We help you organise transcripts, passport details, references, personal statements, and finances."},{"title":"Meet Offer Conditions","description":"Once your offers arrive, we guide you through any pending fees, test requirements, or missing documents."},{"title":"Visa Application","description":"Our visa team supports file preparation, appointment planning, and the key documents embassies need."},{"title":"Fly & Arrive","description":"You receive pre-departure briefings, arrival tips, and practical support before you travel."}]'::jsonb, '{}'::jsonb),
  ('study_abroad', 'requirements', 'Requirements', '', '', '', '', '', '', '', '', '', '', true, 4, '[]'::jsonb, '{"academic":{"badge":"Academic Requirements","heading":"What universities usually look for.","points":["Completed secondary school, diploma, or degree transcripts depending on your level.","Minimum grades that match your chosen course and destination.","Relevant prerequisite subjects for competitive programmes.","English test scores where required by the institution.","Personal statement or motivation letter for selected universities."]},"documents":{"badge":"Document Requirements","heading":"Core documents we help you prepare.","points":["Valid passport bio-data page.","Academic transcripts and certificates.","Curriculum vitae for postgraduate applicants where needed.","Financial documents for tuition and visa processing.","Reference letters, portfolio items, or work history if the programme requires them."]}}'::jsonb),
  ('study_abroad', 'scholarships', 'Scholarships', 'Funding opportunities we can help you track.', 'Scholarship availability changes by university and intake, so we combine live listings with guided recommendations.', '', 'Scholarships', '', '', '', '', '', '', true, 5, '[]'::jsonb, '{}'::jsonb),
  ('study_abroad', 'faq', 'FAQ', 'Questions students ask us all the time.', 'Tap a question below to expand the answer and understand what to expect from the process.', '', 'FAQ', '', '', '', '', '', '', true, 6, '[{"question":"How much does it cost to study abroad?","answer":"Costs depend on destination, programme, and living expenses. We help you compare tuition, accommodation, and visa-related costs before you apply."},{"question":"How long does the process usually take?","answer":"Many students begin 6 to 12 months before their intended intake so there is enough time for applications, offers, and visa preparation."},{"question":"Can Nexora help me find scholarships?","answer":"Yes. We identify scholarships linked to your destination, academics, and university shortlist, then help you apply where possible."},{"question":"Do I need an English proficiency test?","answer":"Some universities require IELTS, TOEFL, Duolingo, or equivalent proof. Requirements vary by country and programme."},{"question":"How does the visa process work?","answer":"Once you meet offer conditions, we prepare your visa file, review your documents, and guide you through booking and submission steps."},{"question":"Can you help with accommodation?","answer":"Yes. We share student accommodation options, on-campus housing guidance, and practical arrival information where available."}]'::jsonb, '{}'::jsonb),
